"""Вейвлет-денойзинг (Haar, MVP)."""from __future__ import annotationsimport numpy as npfrom ..core.types import Signalfrom .base import BaseFilter_SQRT2 = np.sqrt(2.0)def _haar_forward(x: np.ndarray) -> tuple[np.ndarray, np.ndarray]:    a = (x[0::2] + x[1::2]) / _SQRT2    d = (x[0::2] - x[1::2]) / _SQRT2    return a, ddef _haar_inverse(a: np.ndarray, d: np.ndarray) -> np.ndarray:    n = a.size    y = np.empty(2 * n, dtype=np.float64)    y[0::2] = (a + d) / _SQRT2    y[1::2] = (a - d) / _SQRT2    return ydef _soft_threshold(d: np.ndarray, lam: float) -> np.ndarray:    return np.sign(d) * np.maximum(np.abs(d) - lam, 0.0)def _hard_threshold(d: np.ndarray, lam: float) -> np.ndarray:    return np.where(np.abs(d) > lam, d, 0.0)class WaveletDenoiseFilter(BaseFilter):    name = "Вейвлет-денойзинг (Haar, MVP)"    description = ("Многоуровневый Haar-DWT денойзинг с универсальным порогом "                   "Donoho и MAD-оценкой шума. Только базис Хаара.")    params_schema = {        "levels":          {"type": "int", "default": 3,                            "min": 1, "max": 12,                            "label": "Число уровней DWT"},        "mode":            {"type": "enum", "default": "soft",                            "choices": ["soft", "hard"],                            "label": "Тип порога"},        "threshold_scale": {"type": "float", "default": 1.0,                            "min": 0.0, "max": 10.0,                            "label": "Масштаб универсального порога"},    }    def _filter(self, x: np.ndarray, p: dict, signal: Signal) -> np.ndarray:        levels = int(p["levels"])        mode = str(p["mode"])        scale = float(p["threshold_scale"])        n = x.size        factor = 1 << levels        pad_needed = (factor - n % factor) % factor        if pad_needed > 0:            xp = np.pad(x, (0, pad_needed), mode="reflect")        else:            xp = x.copy()        details: list[np.ndarray] = []        a = xp        for _ in range(levels):            a, d = _haar_forward(a)            details.append(d)        finest = details[0]        if finest.size == 0:            raise ValueError(                f"WaveletDenoiseFilter: levels={levels} слишком много "                f"для сигнала длины {n}"            )        mad = float(np.median(np.abs(finest)))        sigma = mad / 0.6745        lam = scale * sigma * np.sqrt(2.0 * np.log(max(xp.size, 2)))        thresh = _soft_threshold if mode == "soft" else _hard_threshold        details = [thresh(d, lam) for d in details]        a_rec = a        for d in reversed(details):            a_rec = _haar_inverse(a_rec, d)        return a_rec[:n].astype(np.float64, copy=False)